#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define db double
const int N=805;
int n,m,x[N],y[N],f[N],cnt;
int find(int x)
{
	if(x==f[x]) return x;
	return f[x]=find(f[x]);
}
db fun(int i,int j)
{
	return sqrt((x[i]-x[j])*(x[i]-x[j])+(y[i]-y[j])*(y[i]-y[j]));
}
struct node
{
	int u,v;
	db num;
	bool operator<(const node other) const
	{
		return num<other.num;
	}
} e[N*N];
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>n>>m;
	for(int i=1;i<=n+1;i++)
	{
		f[i]=i;
	}
	for(int i=1;i<=m;i++)
	{
		cin>>x[i]>>y[i];
	}
	for(int i=1;i<=m;i++)
	{
		for(int j=i+1;j<=m;j++)
		{
			e[++cnt]=node{i,j,fun(i,j)/2};
		}
	}
	for(int i=1;i<=m;i++)
	{
		e[++cnt]=node{i,0,x[i]};
		e[++cnt]=node{i,n+1,n-x[i]};
	}
	sort(e+1,e+1+cnt);
	int num=0;
	while(find(0)!=find(n+1))
	{
		num++;
		int fu=find(e[num].u);
		int fv=find(e[num].v);
		if(fu!=fv) f[fu]=fv;
	}
	cout<<fixed<<setprecision(2)<<e[num].num;
	return 0;
}
